-- Fechamento SC 2026-07-10. Os backfills TSE de patrimonio e financiamento
-- foram aplicados pelo ingest canônico; esta migration preserva os ajustes
-- editoriais/estruturais idempotentes do mesmo fechamento.

UPDATE public.candidatos SET
  nome_completo = 'Laís Chaud', nome_urna = 'Laís Chaud',
  formacao = 'Mestrado em Psicologia pela Universidade Federal de Santa Catarina',
  profissao_declarada = 'Psicóloga',
  fonte_dados = ARRAY['Repositório Institucional da UFSC', 'Unidade Popular', 'G1 Santa Catarina']::text[]
WHERE slug = 'lais-chaud';

INSERT INTO public.historico_politico (
  candidato_id, cargo, cargo_canonico, tipo_evento, periodo_inicio, periodo_fim,
  partido, estado, eleito_por, observacoes, proveniencia
)
SELECT c.id, 'Pré-candidata ao Governo de Santa Catarina', 'Pré-candidata a Governadora',
  'candidatura', 2026, 2026, 'UP', 'SC', 'anúncio partidário',
  'Nome anunciado pela Unidade Popular para a disputa estadual de 2026; não equivale a registro de candidatura deferido no TSE.',
  'manual'
FROM public.candidatos c
WHERE c.slug = 'lais-chaud'
ON CONFLICT (candidato_id, cargo, periodo_inicio) DO UPDATE SET
  cargo_canonico = EXCLUDED.cargo_canonico,
  tipo_evento = EXCLUDED.tipo_evento,
  periodo_fim = EXCLUDED.periodo_fim,
  partido = EXCLUDED.partido,
  estado = EXCLUDED.estado,
  eleito_por = EXCLUDED.eleito_por,
  observacoes = EXCLUDED.observacoes,
  proveniencia = EXCLUDED.proveniencia;

UPDATE public.historico_politico h SET proveniencia =
  CASE WHEN coalesce(h.observacoes, '') ~* 'TSE|ELEITO|NÃO ELEITO|NAO ELEITO' THEN 'tse' ELSE 'manual' END
FROM public.candidatos c
WHERE h.candidato_id = c.id AND c.slug IN ('jorginho-mello', 'joao-rodrigues', 'marcos-vieira') AND h.proveniencia IS NULL;

INSERT INTO public.legislacao_mandato_executivo
  (candidato_id, historico_politico_id, tipo_relacao, esfera, uf_norma, tipo_norma, numero, ano, data_norma, ementa, signatario, autoridade_papel, fonte_primaria_url, fonte_primaria_titulo, identificador_fonte, metadata)
SELECT c.id, h.id, 'lei_sancionada', 'estadual', 'SC', 'lei', '18.807', 2023, '2023-12-21',
  'Institui o PRONAMPE Santa Catarina e disciplina sua operacionalização.', 'JORGINHO MELLO', 'titular',
  'https://leis.alesc.sc.gov.br/ato-normativo/22266', 'ALESC - Lei nº 18.807/2023', 'ALESC:LEI:18807:2023',
  '{"source":"ALESC Leis Estaduais","data_real":true,"coverage_id":"jorginho-mello-sc-executivo-2023-2026-07-10","coverage_scope":"recorte_oficial_verificado","curation_batch_id":"sc-state-completion-20260710","projetos_lei_mixed":false}'::jsonb
FROM public.candidatos c
LEFT JOIN LATERAL (SELECT id FROM public.historico_politico WHERE candidato_id = c.id AND cargo_canonico = 'Governador' LIMIT 1) h ON true
WHERE c.slug = 'jorginho-mello'
  AND NOT EXISTS (SELECT 1 FROM public.legislacao_mandato_executivo l WHERE l.candidato_id = c.id AND l.identificador_fonte = 'ALESC:LEI:18807:2023');


-- Reproduce the canonical TSE money ingest that preceded the SC closeout.
-- Public migrations retain no raw or hashed donor document identifier.
-- The canonical grain of both datasets is one row per candidate/election.
-- Production had non-unique lookup indexes despite containing no duplicate keys;
-- make the invariant explicit before relying on ON CONFLICT below.
CREATE UNIQUE INDEX IF NOT EXISTS uq_patrimonio_candidato_ano_eleicao
  ON public.patrimonio (candidato_id, ano_eleicao);

CREATE UNIQUE INDEX IF NOT EXISTS uq_financiamento_candidato_ano_eleicao
  ON public.financiamento (candidato_id, ano_eleicao);

